import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import {
  fetchMessages, sendTextMessage, sendMediaMessage,
  markChatRead, deleteChatMessage,
} from '../redux/thunks/chatThunks';
import { clearCurrentChat } from '../redux/slices/chatSlice';
import friendService from '../api/services/friendService';
import authService from '../api/services/authService';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './Chat.css';

// Sticker names matching mobile app's sticker system
const STICKERS = [
  'angry', 'confused', 'confusing', 'cool', 'happy', 'love',
  'sad', 'scare', 'sick', 'sleep', 'smiling', 'star', 'surprised',
];

const STICKER_EMOJIS = {
  angry: '😠', confused: '😕', confusing: '🤔', cool: '😎',
  happy: '😊', love: '😍', sad: '😢', scare: '😨',
  sick: '🤒', sleep: '😴', smiling: '😄', star: '🤩', surprised: '😲',
};

const Chat = () => {
  const { recipientId } = useParams();
  const { user } = useSelector((state) => state.auth);
  const { currentMessages, loading, sending, hasMoreMessages } = useSelector((state) => state.chat);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [text, setText] = useState('');
  const [recipient, setRecipient] = useState(null);
  const [showStickers, setShowStickers] = useState(false);
  const [isOnline, setIsOnline] = useState(false);
  const messagesEndRef = useRef(null);
  const messagesContainerRef = useRef(null);
  const fileInputRef = useRef(null);

  // Load recipient profile and messages
  useEffect(() => {
    const loadData = async () => {
      try {
        const res = await friendService.getOtherProfile({ userId: recipientId });
        const profileData = res.data?.data?.customerData || res.data?.data || res.data;
        setRecipient(profileData);
      } catch (err) {
        // Recipient info might come from chat list
      }
    };
    loadData();
    dispatch(fetchMessages({ receiverId: recipientId, skip: 0, limit: 50 }));
    dispatch(markChatRead({ recipientId }));

    return () => {
      dispatch(clearCurrentChat());
    };
  }, [recipientId, dispatch]);

  // Check online status every 90 seconds (matching mobile)
  useEffect(() => {
    const checkOnline = async () => {
      try {
        const res = await authService.getOnlineStatus({ userId: recipientId });
        const data = res.data?.Data ?? res.data?.data ?? res.data;
        setIsOnline(data === 1 || data === true || data?.isOnline === 1 || data?.IsOnline === 1);
      } catch (err) {
        // Ignore
      }
    };
    checkOnline();
    const interval = setInterval(checkOnline, 90000);
    return () => clearInterval(interval);
  }, [recipientId, user?._id]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentMessages.length]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const recipientName = recipient?.fullName || 'User';
  const recipientAvatar = getImageUrl(recipient?.imageURL?.thumbnail || recipient?.imageURL);

  const handleSend = async (e) => {
    e.preventDefault();
    if (!text.trim() || sending) return;
    const msg = text.trim();
    setText('');
    setShowStickers(false);
    await dispatch(sendTextMessage({ receiverId: recipientId, message: msg }));
  };

  const handleSendSticker = async (stickerName) => {
    const emoji = STICKER_EMOJIS[stickerName] || stickerName;
    setShowStickers(false);
    await dispatch(sendTextMessage({ receiverId: recipientId, message: emoji }));
  };

  const handleMediaSelect = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const messageType = file.type.startsWith('video/') ? 'video'
      : file.type.startsWith('audio/') ? 'audio' : 'image';
    await dispatch(sendMediaMessage({ receiverId: recipientId, file, messageType }));
  };

  const handleDeleteMessage = async (messageId) => {
    if (window.confirm('Delete this message?')) {
      await dispatch(deleteChatMessage({ messageId }));
    }
  };

  const handleLoadOlder = useCallback(() => {
    if (!loading && hasMoreMessages) {
      dispatch(fetchMessages({ receiverId: recipientId, skip: currentMessages.length, limit: 50 }));
    }
  }, [dispatch, loading, hasMoreMessages, recipientId, currentMessages.length]);

  const formatTime = (dateStr) => {
    if (!dateStr) return '';
    const d = new Date(dateStr);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="chat-page">
      {/* Header */}
      <div className="chat-header">
        <button className="chat-back-btn" onClick={() => navigate('/messages')}>←</button>
        <div className="chat-header-info">
          {recipientAvatar ? (
            <img src={recipientAvatar} alt="" className="chat-header-avatar" />
          ) : (
            <div className="chat-header-avatar-placeholder">
              {recipientName[0]?.toUpperCase() || 'U'}
            </div>
          )}
          <div>
            <span className="chat-header-name">{recipientName}</span>
            <span className={`chat-header-status ${isOnline ? 'online' : ''}`}>
              {isOnline ? 'Online' : 'Offline'}
            </span>
          </div>
        </div>
        <div className="chat-header-actions">
          <button
            className="chat-call-btn"
            onClick={() => navigate(`/calls?recipientId=${recipientId}&name=${encodeURIComponent(recipientName)}&image=${encodeURIComponent(recipient?.imageURL?.thumbnail || recipient?.imageURL || '')}&type=audio&who=sender`)}
            title="Audio call"
          >
            📞
          </button>
          <button
            className="chat-call-btn"
            onClick={() => navigate(`/calls?recipientId=${recipientId}&name=${encodeURIComponent(recipientName)}&image=${encodeURIComponent(recipient?.imageURL?.thumbnail || recipient?.imageURL || '')}&type=video&who=sender`)}
            title="Video call"
          >
            📹
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="chat-messages" ref={messagesContainerRef}>
        {hasMoreMessages && currentMessages.length > 0 && (
          <button className="chat-load-older" onClick={handleLoadOlder} disabled={loading}>
            {loading ? 'Loading...' : 'Load older messages'}
          </button>
        )}

        {loading && currentMessages.length === 0 && (
          <div className="chat-loading"><div className="page-loading-spinner" /></div>
        )}

        {!loading && currentMessages.length === 0 && (
          <div className="chat-empty">No messages yet. Say hello!</div>
        )}

        {currentMessages.map((msg) => {
          const senderId = msg.senderId?._id || msg.senderId;
          const isMine = senderId === user?._id;
          const mediaUrl = getImageUrl(msg.mediaURL?.original || msg.mediaURL);
          const thumbUrl = getImageUrl(msg.videoThumbnailUrl?.original || msg.videoThumbnailUrl);

          return (
            <div
              key={msg._id}
              className={`chat-bubble-wrap ${isMine ? 'mine' : 'theirs'}`}
            >
              {!isMine && recipientAvatar && (
                <img src={recipientAvatar} alt="" className="chat-bubble-avatar" />
              )}
              <div className={`chat-bubble ${isMine ? 'mine' : 'theirs'}`}>
                {/* Text message */}
                {msg.textMessage && (
                  <p className="chat-bubble-text">{msg.textMessage}</p>
                )}

                {/* Image */}
                {msg.messageType === 'image' && mediaUrl && (
                  <img src={mediaUrl} alt="Shared" className="chat-bubble-image" />
                )}

                {/* Video thumbnail */}
                {msg.messageType === 'video' && (thumbUrl || mediaUrl) && (
                  <div className="chat-bubble-video">
                    <img src={thumbUrl || mediaUrl} alt="Video" className="chat-bubble-image" />
                    <span className="chat-bubble-play">▶</span>
                  </div>
                )}

                {/* Audio */}
                {msg.messageType === 'audio' && mediaUrl && (
                  <audio controls className="chat-bubble-audio">
                    <source src={mediaUrl} />
                  </audio>
                )}

                <span className="chat-bubble-time">{formatTime(msg.createdAt || msg.updatedAt)}</span>
              </div>
              {isMine && (
                <button className="chat-bubble-delete" onClick={() => handleDeleteMessage(msg._id)}>
                  ✕
                </button>
              )}
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Sticker panel */}
      {showStickers && (
        <div className="chat-sticker-panel">
          {STICKERS.map((s) => (
            <button key={s} className="chat-sticker-btn" onClick={() => handleSendSticker(s)}>
              {STICKER_EMOJIS[s]}
            </button>
          ))}
        </div>
      )}

      {/* Input bar */}
      <form className="chat-input-bar" onSubmit={handleSend}>
        <button
          type="button"
          className="chat-sticker-toggle"
          onClick={() => setShowStickers(!showStickers)}
        >
          😊
        </button>
        <label className="chat-media-label">
          📎
          <input
            type="file"
            accept="image/*,video/*,audio/*"
            onChange={handleMediaSelect}
            ref={fileInputRef}
            hidden
          />
        </label>
        <input
          type="text"
          className="chat-text-input"
          placeholder="Write a message..."
          value={text}
          onChange={(e) => setText(e.target.value)}
          disabled={sending}
        />
        <button
          type="submit"
          className={`chat-send-btn ${text.trim() ? 'active' : ''}`}
          disabled={!text.trim() || sending}
        >
          ➤
        </button>
      </form>
    </div>
  );
};

export default Chat;
