import { nodeApi, dotnetApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData, getNode, putNoBody, putFormData } from '../helpers';

/**
 * Auth service — matches mobile app's exact service patterns per action.
 * See actions/auth_actions.js for which service each call uses.
 */
const authService = {
  // LoginAttempt → post_services (BASE_URL, FormData)
  login: (formData) => nodeApi.post(ENDPOINTS.LOGIN, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // SignUpAttempt → post_services (BASE_URL, FormData)
  register: (formData) => nodeApi.post(ENDPOINTS.REGISTER, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // SocialLoginAttempt → post_services (BASE_URL, FormData)
  loginGoogle: (params) => postFormData(nodeApi, ENDPOINTS.LOGIN_GOOGLE, params),
  // ForgotPasswordAttempt → post_services (BASE_URL, FormData)
  forgotPassword: (params) => postFormData(nodeApi, ENDPOINTS.FORGOT_PASSWORD, params),
  // VerifyOtpAttempt → post_services (BASE_URL, FormData)
  verifyOtp: (params) => postFormData(nodeApi, ENDPOINTS.VERIFY_OTP, params),
  // ResetPasswordAttempt → post_services (BASE_URL, FormData)
  resetPassword: (params) => postFormData(nodeApi, ENDPOINTS.RESET_PASSWORD, params),
  // ChangePasswordAttempt → post_services (BASE_URL, FormData + token)
  changePassword: (params) => postFormData(nodeApi, ENDPOINTS.CHANGE_PASSWORD, params),
  // LogoutAttempt → put_services (BASE_URL, PUT, no body)
  logout: () => putNoBody(nodeApi, ENDPOINTS.LOGOUT),
  // getProfile → GET (CORS passes with capital 'Authorization' header)
  getProfile: () => getNode(nodeApi, ENDPOINTS.GET_PROFILE),
  // EditProfileAttempt → post_services (BASE_URL, FormData + token)
  saveProfile: (params) => postFormData(nodeApi, ENDPOINTS.SAVE_PROFILE, params),
  // ProfilePicAttempt → post_services (BASE_URL, FormData multipart + token)
  uploadProfilePic: (formData) => nodeApi.post(ENDPOINTS.UPLOAD_PROFILE_PIC, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // BannerPicAttempt → post_services (BASE_URL, FormData multipart + token)
  uploadBanner: (formData) => nodeApi.post(ENDPOINTS.UPLOAD_BANNER, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // video upload → post_services (BASE_URL, FormData multipart + token)
  updateVideo: (formData) => nodeApi.post(ENDPOINTS.UPDATE_VIDEO, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  // wallpaper → post_services (BASE_URL, FormData)
  updateWallpaper: (params) => postFormData(nodeApi, ENDPOINTS.UPDATE_WALLPAPER, params),
  // updateUserType → raw fetch to BASE_URL_5 (.NET JSON)
  updateUserType: (data) => dotnetApi.post(ENDPOINTS.UPDATE_USER_TYPE, data, {
    headers: { 'Content-Type': 'application/json' },
  }),
  // online status → .NET Customer endpoint POST
  getOnlineStatus: (data) => dotnetApi.post(ENDPOINTS.GET_ONLINE_STATUS, data),
  setOnlineStatus: (data) => dotnetApi.post(ENDPOINTS.SET_ONLINE_STATUS, data),
};

export default authService;
